#### 数据预处理

##### 实际使用的预处理函数

```
// apps/web/app/[deviceTheme]/[region]/[locale]/[...rest]/utils/content-processor.ts

// 工具函数：处理整个页面内容
export const processPageContent = (
  content: any,
  cookieContext: { cookies: any },
  dyCampaignsData: Record<string, any>
): ProcessItemsResult => {
  const dyCampaignPromises: Promise<void>[] = [];
  let hasFaqSchema = false;
  let jsonLd: WithContext<FAQPage> = {
    '@type': 'FAQPage',
    '@context': 'https://schema.org',
  };

  // 1. 处理 story.content.body
  const bodyResult = processItems(content?.body || [], cookieContext, dyCampaignsData);

  // 2. 合并结果
  dyCampaignPromises.push(...bodyResult.dyCampaignPromises);
  hasFaqSchema = bodyResult.hasFaqSchema;
  jsonLd = bodyResult.jsonLd;

  // 3. 处理包含 items 的组件（如 Hero 组件）
  for (const item of content?.body || []) {
    const componentResult = processComponentWithItems(item, cookieContext, dyCampaignsData);
    if (componentResult) {
      dyCampaignPromises.push(...componentResult.dyCampaignPromises);
      if (componentResult.hasFaqSchema) {
        hasFaqSchema = componentResult.hasFaqSchema;
        jsonLd = componentResult.jsonLd;
      }
    }
  }

  return {
    dyCampaignPromises,
    hasFaqSchema,
    jsonLd,
  };
};
```

##### 在页面中的使用

```
// apps/web/app/[deviceTheme]/[region]/[locale]/home/page.tsx
// apps/web/app/[deviceTheme]/[region]/[locale]/[...rest]/page.tsx

export default async function Page({ params }) {
  const story = await queryPageBySlug({ slug: rest.join('/') });
  const dyCampaignsData: Record<string, any> = {};
  const cookieContext = { cookies };

  // 使用工具函数处理页面内容
  const contentResult = processPageContent(story.content, cookieContext, dyCampaignsData);

  // 并行执行所有异步请求
  const asyncPromises: Promise<any>[] = [];
  asyncPromises.push(...contentResult.dyCampaignPromises);

  if (asyncPromises.length > 0) {
    await Promise.all(asyncPromises);
  }

  return (
    <>
      {contentResult.hasFaqSchema && <JsonLd code={contentResult.jsonLd} />}
      <StoryblokPageContent content={story.content} />
    </>
  );
}
```

##### 处理内容

- FAQ Schema 生成：从 Accordion 组件提取问题，生成结构化数据
- DY Campaign 数据获取：并行获取所有 Dynamic Yield 活动数据
- 组件嵌套处理：递归处理包含 items 的组件（如 Hero、Listing 等）
##### 优化点

- 模块化设计：将处理逻辑拆分为 processItems、processComponentsWithItems 等工具函数
